const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;

return [{ tenantId }];

const aggregateData = $node['query_aggregate_stats'].json.data || [];
const bestCampaignsData = $node['query_best_campaigns'].json.data || [];
const monthlySendsData = $node['query_monthly_sends'].json.data || [];
const activeSubscribersData = $node['query_active_subscribers'].json.data || [];

const aggregateStats = aggregateData.length > 0 ? aggregateData[0] : {};

const totalSent = parseInt(aggregateStats.total_sent) || 0;
const totalEnvoyes = parseInt(aggregateStats.total_envoyes) || 0;
const totalOuverts = parseInt(aggregateStats.total_ouverts) || 0;
const totalCliques = parseInt(aggregateStats.total_cliques) || 0;

const avgOpenRate = totalEnvoyes > 0 ? (totalOuverts / totalEnvoyes * 100).toFixed(2) : 0;
const avgClickRate = totalEnvoyes > 0 ? (totalCliques / totalEnvoyes * 100).toFixed(2) : 0;

const bestCampaigns = bestCampaignsData.map(row => ({
  name: row.name,
  subject: row.subject,
  openRate: parseFloat(row.open_rate).toFixed(2),
  clickRate: parseFloat(row.click_rate).toFixed(2)
}));

const monthlySends = monthlySendsData.map(row => ({
  month: row.month,
  campaignCount: parseInt(row.campaign_count) || 0,
  totalEnvoyes: parseInt(row.total_envoyes) || 0
}));

const totalActiveSubscribers = activeSubscribersData.length > 0 ? parseInt(activeSubscribersData[0].count) || 0 : 0;

return [{
  json: {
    analytics: {
      totalSent: totalSent,
      totalEnvoyes: totalEnvoyes,
      totalOuverts: totalOuverts,
      totalCliques: totalCliques,
      avgOpenRate: parseFloat(avgOpenRate),
      avgClickRate: parseFloat(avgClickRate),
      bestCampaigns: bestCampaigns,
      monthlySends: monthlySends,
      totalActiveSubscribers: totalActiveSubscribers
    }
  }
}];
